    // CBOR key: node_id
    public required NodeId NodeId { get; init; }
    // CBOR key: friendly_name
    public required string FriendlyName { get; init; }

    /// <summary>Throws System.ArgumentException when a field violates a CSIL constraint.</summary>
    public void Validate()
    {
        if (FriendlyName.Length < 1)
        {
            throw new System.ArgumentException("field 'FriendlyName' must have at least 1 elements");
        }
        if (FriendlyName.Length > 64)
        {
            throw new System.ArgumentException("field 'FriendlyName' must have at most 64 elements");
        }
    }
}

